  # Group triples by subject to build a single coherent sentence
      groups: dict[str, list[str]] = {}
      def _format_object(pred: str, obj: str) -> str:
          """Add appropriate units or phrasing based on predicate."""
          # Numeric values may be given as strings; try to detect numbers
          try:
              num = float(obj)
              is_number = True
          except Exception:
              is_number = False

          if pred.endswith("Feet") and is_number:
              return f"{obj} feet"
          if pred.endswith("Metre") and is_number:
              return f"{obj} metres"
          if pred in ("elevationAboveTheSeaLevel", "elevationAboveTheSeaLevelInFeet",
                      "elevationAboveTheSeaLevelInMetres"):
              # Provide a more natural phrase for elevation
              if pred == "elevationAboveTheSeaLevelInFeet" and is_number:
                  return f"{obj} feet above sea level"
              if pred == "elevationAboveTheSeaLevelInMetres" and is_number:
                  return f"{obj} metres above sea level"
              return f"{obj} metres above sea level"
          return obj

      for t in triples:
          verb = verb_map.get(t.predicate, "has")
          obj_formatted = _format_object(t.predicate, str(t.object))
          phrase = f"{verb} {obj_formatted}"
          groups.setdefault(t.subject, []).append(phrase)
